external_knowledge:
- 'highest commenting activity' refers to categories with the most comments; 
- 'best average ratings' refers to categories with higher average ratings, indicating better content quality; 
- 'top tags' refer to the most frequently occurring tags within each category.

sql:
SELECT COUNT(view_id) AS view_count
FROM post_views
WHERE post_id = 1;

SELECT title
FROM posts
ORDER BY views DESC, comments_count DESC, average_rating DESC;

